/**
 * IWAC Visualizations — Collection Overview block
 *
 * Renders the Collection Overview page block by:
 *   1. Fetching asset/data/collection-overview.json (generated by
 *      scripts/generate_collection_overview.py)
 *   2. Rendering a row of summary stat cards
 *   3. Rendering four ECharts charts via IWACVis.registerChart so they
 *      re-theme automatically when the IWAC theme toggles light/dark
 *
 * Expected container:
 *   <div class="iwac-vis-overview"
 *        data-base-path="/s/..."
 *        data-site-base="/s/sitename">
 *     <div class="iwac-vis-loading">...</div>
 *   </div>
 */
(function () {
    'use strict';

    var ns = window.IWACVis;
    if (!ns) {
        console.warn('IWACVis namespace not found — did dashboard-core.js load?');
        return;
    }

    /* ----------------------------------------------------------------- */
    /*  Entity type labels                                                */
    /* ----------------------------------------------------------------- */

    // Map JSON keys (French, from the HF `index` subset) to i18n keys.
    var ENTITY_TYPE_I18N = {
        'Personnes':    'Persons',
        'Organisations': 'Organizations',
        'Lieux':        'Places',
        'Sujets':       'Subjects',
        '\u00c9v\u00e9nements': 'Events'
    };

    var ENTITY_TYPE_ORDER = ['Personnes', 'Organisations', 'Lieux', 'Sujets', '\u00c9v\u00e9nements'];

    /* ----------------------------------------------------------------- */
    /*  Helpers                                                           */
    /* ----------------------------------------------------------------- */

    function el(tag, className, text) {
        var node = document.createElement(tag);
        if (className) node.className = className;
        if (text != null) node.textContent = text;
        return node;
    }

    function escapeHtml(str) {
        return String(str).replace(/[&<>"']/g, function (c) {
            return ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' })[c];
        });
    }

    function formatNumber(n) {
        return ns.formatNumber ? ns.formatNumber(n) : String(n);
    }

    function t(key, params) { return ns.t(key, params); }

    /* ----------------------------------------------------------------- */
    /*  Layout                                                            */
    /* ----------------------------------------------------------------- */

    /** Build the static DOM for the overview. Charts get initialized after. */
    function buildLayout(container, data) {
        container.innerHTML = '';

        var root = el('div', 'iwac-vis-overview-root');
        container.appendChild(root);

        // --- Summary cards row ---
        var summary = data.summary || {};
        var cards = [
            { key: 'Articles',     value: summary.articles },
            { key: 'Publications', value: summary.publications },
            { key: 'Entities',     value: summary.index_entries },
            { key: 'References',   value: summary.references },
            { key: 'Countries',    value: summary.countries },
            { key: 'Languages',    value: summary.languages }
        ];
        var cardsEl = el('div', 'iwac-vis-overview-summary');
        cards.forEach(function (c) {
            if (c.value == null) return;
            var card = el('div', 'iwac-vis-summary-card');
            card.appendChild(el('div', 'iwac-vis-summary-card__value', formatNumber(c.value)));
            card.appendChild(el('div', 'iwac-vis-summary-card__label', t(c.key)));
            cardsEl.appendChild(card);
        });
        root.appendChild(cardsEl);

        // --- Year range subtitle (if available) ---
        if (summary.year_min && summary.year_max) {
            var range = el('p', 'iwac-vis-overview-subtitle');
            range.textContent =
                t('Across') + ' ' + t('year_range', { min: summary.year_min, max: summary.year_max });
            root.appendChild(range);
        }

        // --- Charts grid ---
        var grid = el('div', 'iwac-vis-overview-grid');
        root.appendChild(grid);

        // Timeline — full width
        var timelinePanel = buildPanel(
            'iwac-vis-panel iwac-vis-panel--wide',
            t('Items per year, by country')
        );
        grid.appendChild(timelinePanel.panel);

        // Country bar
        var countryPanel = buildPanel('iwac-vis-panel', t('Content by country'));
        grid.appendChild(countryPanel.panel);

        // Language bar
        var languagePanel = buildPanel('iwac-vis-panel', t('Languages represented'));
        grid.appendChild(languagePanel.panel);

        // Top entities — full width, with type tabs
        var entitiesPanel = buildPanel(
            'iwac-vis-panel iwac-vis-panel--wide',
            t('Most-cited entities')
        );
        entitiesPanel.panel.classList.add('iwac-vis-entities-panel');

        // Entity type tabs
        var tabs = el('div', 'iwac-vis-tabs');
        var availableTypes = ENTITY_TYPE_ORDER.filter(function (type) {
            var list = (data.top_entities && data.top_entities[type]) || [];
            return list.length > 0;
        });
        if (availableTypes.length === 0) {
            entitiesPanel.chart.appendChild(
                el('div', 'iwac-vis-empty', t('No data available'))
            );
        } else {
            availableTypes.forEach(function (type, idx) {
                var btn = el('button', 'iwac-vis-tab', t(ENTITY_TYPE_I18N[type] || type));
                btn.type = 'button';
                btn.dataset.entityType = type;
                if (idx === 0) btn.classList.add('iwac-vis-tab--active');
                tabs.appendChild(btn);
            });
        }
        entitiesPanel.panel.insertBefore(tabs, entitiesPanel.chart);
        grid.appendChild(entitiesPanel.panel);

        return {
            timeline:  timelinePanel.chart,
            country:   countryPanel.chart,
            language:  languagePanel.chart,
            entities:  entitiesPanel.chart,
            tabs:      tabs,
            activeType: availableTypes[0] || null
        };
    }

    function buildPanel(className, titleText) {
        var panel = el('div', className);
        panel.appendChild(el('h4', null, titleText));
        var chart = el('div', 'iwac-vis-chart');
        panel.appendChild(chart);
        return { panel: panel, chart: chart };
    }

    /* ----------------------------------------------------------------- */
    /*  Chart option builders                                             */
    /* ----------------------------------------------------------------- */

    function buildTimelineOption(timeline) {
        var years = timeline.years || [];
        var countries = timeline.countries || [];
        var series = countries.map(function (country) {
            return {
                name: country,
                type: 'bar',
                stack: 'total',
                barMaxWidth: 28,
                emphasis: { focus: 'series' },
                data: (timeline.series && timeline.series[country]) || []
            };
        });

        var useZoom = years.length > 20;
        return {
            grid: { left: 48, right: 16, top: 48, bottom: useZoom ? 56 : 32 },
            legend: {
                type: 'scroll',
                top: 4,
                itemWidth: 12,
                itemHeight: 10
            },
            tooltip: {
                trigger: 'axis',
                axisPointer: { type: 'shadow' }
            },
            xAxis: {
                type: 'category',
                data: years,
                name: t('Year'),
                nameLocation: 'middle',
                nameGap: useZoom ? 36 : 24
            },
            yAxis: {
                type: 'value',
                name: t('Count')
            },
            dataZoom: useZoom
                ? [
                      { type: 'slider', start: 60, end: 100, bottom: 8, height: 18 },
                      { type: 'inside' }
                  ]
                : [],
            series: series
        };
    }

    function buildHorizontalBarOption(entries, nameKey, valueKey) {
        // entries: [{ name, total/count }]
        var names = entries.map(function (e) { return e[nameKey]; });
        var values = entries.map(function (e) { return e[valueKey]; });
        return {
            grid: { left: 8, right: 24, top: 8, bottom: 8, containLabel: true },
            tooltip: {
                trigger: 'axis',
                axisPointer: { type: 'shadow' }
            },
            xAxis: { type: 'value' },
            yAxis: {
                type: 'category',
                data: names,
                inverse: true,
                axisTick: { show: false }
            },
            series: [
                {
                    type: 'bar',
                    data: values,
                    barMaxWidth: 22,
                    label: {
                        show: true,
                        position: 'right',
                        formatter: function (p) { return formatNumber(p.value); }
                    }
                }
            ]
        };
    }

    function buildEntityOption(entries) {
        var names = entries.map(function (e) { return e.title; });
        var values = entries.map(function (e) { return e.frequency; });
        var ids = entries.map(function (e) { return e.o_id; });
        return {
            grid: { left: 8, right: 48, top: 8, bottom: 8, containLabel: true },
            tooltip: {
                trigger: 'item',
                formatter: function (p) {
                    var entry = entries[p.dataIndex] || {};
                    var lines = [
                        '<strong>' + escapeHtml(entry.title || '') + '</strong>',
                        t('mentions_count', { count: formatNumber(entry.frequency || 0) })
                    ];
                    if (entry.first_occurrence || entry.last_occurrence) {
                        lines.push(
                            (entry.first_occurrence || '?') + ' – ' + (entry.last_occurrence || '?')
                        );
                    }
                    if (entry.countries && entry.countries.length) {
                        lines.push(entry.countries.join(', '));
                    }
                    return lines.join('<br>');
                }
            },
            xAxis: { type: 'value' },
            yAxis: {
                type: 'category',
                data: names,
                inverse: true,
                axisTick: { show: false }
            },
            series: [
                {
                    type: 'bar',
                    data: values.map(function (v, i) {
                        return { value: v, o_id: ids[i] };
                    }),
                    barMaxWidth: 20,
                    label: {
                        show: true,
                        position: 'right',
                        formatter: function (p) { return formatNumber(p.value); }
                    },
                    cursor: 'pointer'
                }
            ]
        };
    }

    /* ----------------------------------------------------------------- */
    /*  Main controller                                                   */
    /* ----------------------------------------------------------------- */

    function initOverview(container) {
        var basePath = container.dataset.basePath || '';
        var siteBase = container.dataset.siteBase || '';
        var url = basePath + '/modules/IwacVisualizations/asset/data/collection-overview.json';

        fetch(url)
            .then(function (r) {
                if (!r.ok) throw new Error('HTTP ' + r.status);
                return r.json();
            })
            .then(function (data) {
                var handles = buildLayout(container, data);

                // Timeline
                if (data.timeline && (data.timeline.years || []).length > 0) {
                    ns.registerChart(handles.timeline, function (el, chart) {
                        chart.setOption(buildTimelineOption(data.timeline));
                    });
                } else {
                    handles.timeline.appendChild(el('div', 'iwac-vis-empty', t('No data available')));
                }

                // Country
                var countries = (data.countries || []).slice(0, 10);
                if (countries.length > 0) {
                    ns.registerChart(handles.country, function (el, chart) {
                        chart.setOption(buildHorizontalBarOption(countries, 'name', 'total'));
                    });
                } else {
                    handles.country.appendChild(el('div', 'iwac-vis-empty', t('No data available')));
                }

                // Language
                var languages = (data.languages || []).slice(0, 10);
                if (languages.length > 0) {
                    ns.registerChart(handles.language, function (el, chart) {
                        chart.setOption(buildHorizontalBarOption(languages, 'name', 'count'));
                    });
                } else {
                    handles.language.appendChild(el('div', 'iwac-vis-empty', t('No data available')));
                }

                // Entities — tabbed
                if (handles.activeType) {
                    var entities = (data.top_entities && data.top_entities[handles.activeType]) || [];
                    var entityChart = ns.registerChart(handles.entities, function (el, chart) {
                        var currentEntries = entities;
                        chart.setOption(buildEntityOption(currentEntries));
                    });

                    // Click-through to Omeka item page
                    if (entityChart) {
                        entityChart.on('click', function (params) {
                            var item = params.data;
                            if (item && item.o_id && siteBase) {
                                window.location.href = siteBase + '/item/' + item.o_id;
                            }
                        });
                    }

                    // Tab switching — rebuild the option with the new type's entries
                    handles.tabs.addEventListener('click', function (evt) {
                        var btn = evt.target.closest('[data-entity-type]');
                        if (!btn) return;
                        var type = btn.dataset.entityType;
                        if (!type || type === handles.activeType) return;
                        handles.activeType = type;
                        // Update active state
                        handles.tabs.querySelectorAll('.iwac-vis-tab').forEach(function (b) {
                            b.classList.toggle('iwac-vis-tab--active', b === btn);
                        });
                        // Replace the entity chart's registered render fn by
                        // disposing and re-registering. Simpler: just setOption
                        // on the existing chart with the new entries.
                        if (entityChart && !entityChart.isDisposed()) {
                            var nextEntries = (data.top_entities && data.top_entities[type]) || [];
                            entityChart.setOption(buildEntityOption(nextEntries), true);
                        }
                    });
                }
            })
            .catch(function (err) {
                console.error('IWACVis overview:', err);
                container.innerHTML = '';
                var errEl = el('div', 'iwac-vis-error', t('Failed to load'));
                container.appendChild(errEl);
            });
    }

    /* ----------------------------------------------------------------- */
    /*  Auto-init                                                         */
    /* ----------------------------------------------------------------- */

    function init() {
        if (typeof echarts === 'undefined') {
            console.warn('IWACVis overview: ECharts not loaded');
            return;
        }
        var containers = document.querySelectorAll('.iwac-vis-overview');
        for (var i = 0; i < containers.length; i++) {
            initOverview(containers[i]);
        }
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }
})();
